using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private readonly ServiceRegistry _registry;

    public ServiceRegistryTests()
    {
        _registry = new ServiceRegistry();
    }

    [TestMethod]
    public void Register_WithValidService_StoresService()
    {
        // Arrange
        var service = new FakeService();

        // Act
        _registry.Register<IFakeService>(service);

        // Assert
        var resolved = _registry.Resolve<IFakeService>();
        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Register_WithNull_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _registry.Register<IFakeService>(null!));
        Assert.AreEqual("service", ex.ParamName);
    }

    [TestMethod]
    public void Register_CalledTwice_OverwritesPrevious()
    {
        // Arrange
        var first = new FakeService();
        var second = new FakeService();

        // Act
        _registry.Register<IFakeService>(first);
        _registry.Register<IFakeService>(second);

        // Assert
        var resolved = _registry.Resolve<IFakeService>();
        Assert.AreSame(second, resolved);
    }

    [TestMethod]
    public void Resolve_WhenRegistered_ReturnsSameInstance()
    {
        // Arrange
        var service = new FakeService();
        _registry.Register<IFakeService>(service);

        // Act
        var first = _registry.Resolve<IFakeService>();
        var second = _registry.Resolve<IFakeService>();

        // Assert
        Assert.AreSame(first, second);
    }

    [TestMethod]
    public void Resolve_WhenNotRegistered_ReturnsNull()
    {
        // Act
        var result = _registry.Resolve<IFakeService>();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ResolveRequired_WhenRegistered_ReturnsService()
    {
        // Arrange
        var service = new FakeService();
        _registry.Register<IFakeService>(service);

        // Act
        var result = _registry.ResolveRequired<IFakeService>();

        // Assert
        Assert.AreSame(service, result);
    }

    [TestMethod]
    public void ResolveRequired_WhenNotRegistered_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _registry.ResolveRequired<IFakeService>());
        Assert.Contains(ex.Message, nameof(IFakeService));
    }

    [TestMethod]
    public void GetAll_WhenEmpty_ReturnsEmptyCollection()
    {
        // Act
        var result = _registry.GetAll();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetAll_WithMultipleServices_ReturnsAll()
    {
        // Arrange
        var fakeService = new FakeService();
        var otherService = new OtherFakeService();
        _registry.Register<IFakeService>(fakeService);
        _registry.Register<IOtherFakeService>(otherService);

        // Act
        var result = _registry.GetAll();

        // Assert
        Assert.HasCount(2, result);
        Assert.Contains(fakeService, result);
        Assert.Contains(otherService, result);
    }

    [TestMethod]
    public void Remove_WhenRegistered_RemovesService()
    {
        // Arrange
        var service = new FakeService();
        _registry.Register<IFakeService>(service);

        // Act
        _registry.Remove<IFakeService>();

        // Assert
        Assert.IsNull(_registry.Resolve<IFakeService>());
    }

    [TestMethod]
    public void Remove_WhenNotRegistered_DoesNotThrow()
    {
        // Act & Assert -- no exception
        _registry.Remove<IFakeService>();
    }

    [TestMethod]
    public void Clear_RemovesAllServices()
    {
        // Arrange
        _registry.Register<IFakeService>(new FakeService());
        _registry.Register<IOtherFakeService>(new OtherFakeService());

        // Act
        _registry.Clear();

        // Assert
        Assert.IsNull(_registry.Resolve<IFakeService>());
        Assert.IsNull(_registry.Resolve<IOtherFakeService>());
        Assert.IsEmpty(_registry.GetAll());
    }

    [TestMethod]
    public void Register_MultipleDifferentTypes_AllResolvable()
    {
        // Arrange
        var fakeService = new FakeService();
        var otherService = new OtherFakeService();

        // Act
        _registry.Register<IFakeService>(fakeService);
        _registry.Register<IOtherFakeService>(otherService);

        // Assert
        Assert.AreSame(fakeService, _registry.Resolve<IFakeService>());
        Assert.AreSame(otherService, _registry.Resolve<IOtherFakeService>());
    }

    private interface IFakeService;
    private interface IOtherFakeService;
    private sealed class FakeService : IFakeService;
    private sealed class OtherFakeService : IOtherFakeService;
}

